use strict;
use warnings;
use PDF::API2;
use PDF::API2::PDF::TableExtract;

# specify the pdf file
my $pdf_file = 'example.pdf';

# load the pdf file
my $pdf = PDF::API2->open($pdf_file);

# extract metadata
my $info = $pdf->info;
my $date = $info->Get('ModDate');
my $author = $info->Get('Author');

print "Date: $date\n";
print "Author: $author\n";

# extract tables
my $te = PDF::API2::PDF::TableExtract->new({
    pdf => $pdf,
    x_tolerance => 5,
    textsearch => 1,
    row_filter => sub { return 1; },  # keep all rows
});

my $tables = $te->tables;

foreach my $table (@$tables) {
    print "Table:\n";
    foreach my $row (@{$table->{rows}}) {
        foreach my $cell (@{$row->{cells}}) {
            print $cell, "\t";
        }
        print "\n";
    }
    print "\n";
}

$pdf->close;
